package br.com.gustavohenrique.cleanmediasapi;

import org.junit.jupiter.api.Test;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.test.context.TestPropertySource;

// Smoke test: verifica que o contexto Spring sobe sem erros.
// Usa H2 em memória para não depender de MySQL no CI/CD.
@SpringBootTest
@TestPropertySource(properties = {
        "spring.datasource.url=jdbc:h2:mem:testdb;DB_CLOSE_DELAY=-1",
        "spring.datasource.driver-class-name=org.h2.Driver",
        "spring.datasource.username=sa",
        "spring.datasource.password=",
        "spring.jpa.properties.hibernate.dialect=org.hibernate.dialect.H2Dialect",
        "spring.jpa.hibernate.ddl-auto=create-drop",
        "spring.flyway.enabled=false",
        // Chaves RSA de teste (mesmas do JwtServiceTest)
        "jwt.public-",
        "jwt.private-"
})
class CleanMediasApiApplicationTest {

    @Test
    void contextLoads() {
        // passa se o contexto sobe sem exceção
    }
}
